const jobs = $input.first().json.data || [];

// Filter ONLY Frankfurt/Germany jobs
const frankfurtJobs = jobs.filter(job => {
  const location = (job.location || '').toLowerCase();
  return location.includes('frankfurt') || 
         location.includes('germany') ||
         location.includes('deutschland') ||
         location.includes('de');
});

// Take first 20
const trimmedJobs = frankfurtJobs.slice(0, 20);

// Keep only needed fields
const cleanJobs = trimmedJobs.map(job => ({
  title: job.title || 'N/A',
  company_name: job.company_name || 'N/A',
  location: job.location || 'N/A',
  tags: job.tags || [],
  url: job.url || '',
  remote: job.remote || false,
  created_at: job.created_at || ''
}));

return [{ json: { data: cleanJobs } }];

