// Get Groq response
const response = $input.first().json;
const content = response.choices[0].message.content;

// Clean and parse JSON
const clean = content.replace(/```json/g, '').replace(/```/g, '').trim();
const analysis = JSON.parse(clean);

// Format into nice HTML report
const date = new Date().toDateString();

const html = `
<html>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">

<h1 style="color: #1E3A5F; border-bottom: 3px solid #2980B9; padding-bottom: 10px;">
  🤖 Daily Job Market Intelligence
</h1>
<p style="color: #666;">Report Date: ${date}</p>

<h2 style="color: #2980B9;">📈 Top In-Demand Roles</h2>
<ul>
${(analysis.top_roles || []).map(r => `<li style="margin: 5px 0;">${r}</li>`).join('')}
</ul>

<h2 style="color: #2980B9;">🛠️ Most Requested Skills</h2>
<ul>
${(analysis.top_skills || []).map(s => `<li style="margin: 5px 0;">${s}</li>`).join('')}
</ul>

<h2 style="color: #2980B9;">💻 Remote vs Onsite</h2>
<p>${analysis.remote_trend || 'N/A'}</p>

<h2 style="color: #2980B9;">📍 Geographic Hotspots</h2>
<p>${Array.isArray(analysis.locations) ? analysis.locations.join(', ') : analysis.locations || 'N/A'}</p>

<h2 style="color: #2980B9;">📋 Market Summary</h2>
<p style="background: #f0f4f8; padding: 15px; border-radius: 5px; line-height: 1.6;">
${analysis.summary || 'N/A'}
</p>

<hr style="border: 1px solid #eee; margin-top: 30px;">
<p style="color: #999; font-size: 12px;">
  Generated by Automated Job Market Intelligence System
</p>

</body>
</html>
`;

return [{ 
  json: { 
    html_report: html,
    analysis: analysis,
    date: date
  } 
}];
